// And groups predicates with the AND operator between them.
func And(predicates ...predicate.BOMHeader) predicate.BOMHeader {
	return predicate.BOMHeader(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.BOMHeader) predicate.BOMHeader {
	return predicate.BOMHeader(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.BOMHeader) predicate.BOMHeader {
	return predicate.BOMHeader(sql.NotPredicates(p))
}
